const char32_t* GetUILocalizedString(uint32_t stringID, UILanguage language)
{
    auto it = g_TranslationMap.find(stringID);
    if (it == g_TranslationMap.end()){
        return U"";
    }

    const size_t langIdx = static_cast<size_t>(language);
    if (langIdx >= static_cast<size_t>(UILanguage::COUNT)){
        return it->second[0];
    }

    const char32_t* str = it->second[langIdx];
    if (str == nullptr || *str == U'\0'){
        return it->second[0];
    }

    return str;
}
